module D_ff_posedge_async_reset(output Q, Qn, input rst_l, D, clk);

    reg X_Q_reg, Qn_reg;
    wire D_bar;

    assign D_bar = ~D;

    always @(posedge clk or negedge rst_l) begin
        if (~rst_l) begin
            X_Q_reg <= 1'b0;
            Qn_reg <= 1'b1;
        end
        else begin
            X_Q_reg <= D;
            Qn_reg <= D_bar;
        end
    end

    assign Q = X_Q_reg;
    assign Qn = Qn_reg;

endmodule
